class Solution {
    public int lengthAfterTransformation(String s, int t, List<Integer> nums) {
        int result = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            int index = (int) (nums.get(c - 'a') + t;
            result = (result + index) % 1000000007;
        }
        return result;
    }
}
